mapper.select:
SELECT id, user_id, type, title, content, target_type, target_id, event_key, read_at, deleted_at, created_at
FROM notifications
WHERE user_id = #{userId}
  AND deleted_at IS NULL
ORDER BY created_at DESC
LIMIT #{limit} OFFSET #{offset}

mapper.update:
UPDATE notifications
SET read_at = #{readAt}
WHERE id = #{id}
  AND user_id = #{userId}
  AND read_at IS NULL

UPDATE notifications
SET read_at = #{readAt}
WHERE user_id = #{userId}
  AND read_at IS NULL
  AND deleted_at IS NULL

UPDATE notifications
SET deleted_at = #{deletedAt}
WHERE id = #{id}
  AND user_id = #{userId}
  AND deleted_at IS NULL

UPDATE notifications
SET deleted_at = #{deletedAt}
WHERE user_id = #{userId}
  AND deleted_at IS NULL
